window.bookSummaryJSON = "<p><i>New York Times</i> best-selling author Eric Flint’s <i>1632</i> presented listeners with a fascinating alternate history of the Thirty Years’ War, through the eyes of a West Virginia community tossed back in time to 17th-century Germany. Here, Flint teams up with acclaimed science fiction author David Weber to continue his epic tale. In <i>1633</i>, the West Virginians attempt to use their modern-day knowledge to build a resistance against the forces of France, Spain, and England.</p>"; 
